let locks = 0; let prev = '';
export function useScrollLock(active: boolean){
  useEffect(()=>{ if(!active) return;
    if(locks===0){ prev = document.body.style.overflow; document.body.style.overflow='hidden'; }
    locks++;
    return ()=>{ locks=Math.max(0,locks-1); if(locks===0) document.body.style.overflow=prev; };
  },[active]);
}

